// frontend/src/pages/Login.js
import React from 'react';
import { useNavigate } from 'react-router-dom';

export default function Login() {
  const navigate = useNavigate();

  const handleStart = () => {
    // Chuyển người chơi đến Dòng chảy thời gian
    navigate('/timeline');
  };

  return (
    <div className="flex flex-col items-center justify-center h-screen bg-yellow-100">
      <h1 className="text-3xl font-bold text-red-800 mb-6">Khám Phá Lịch Sử Việt Nam</h1>
      <input type="text" placeholder="Tên danh tướng của bạn" className="p-2 border border-yellow-600 rounded mb-4 w-64 text-center" />
      <button onClick={handleStart} className="bg-yellow-700 hover:bg-yellow-800 text-white font-bold px-6 py-3 rounded shadow-lg transition duration-300">
        Bắt Đầu Hành Trình
      </button>
    </div>
  );
}
